export default function handlePagination(updateProductsList) {
  const paginationContainer = document.querySelector("#products-pagination");
  const pagesContainer = paginationContainer.querySelector(
    ".unavailable__pagination-pages"
  );
  const firstButton = paginationContainer.querySelector(
    ".unavailable__pagination-btn--first"
  );
  const prevButton = paginationContainer.querySelector(
    ".unavailable__pagination-btn--prev"
  );
  const nextButton = paginationContainer.querySelector(
    ".unavailable__pagination-btn--next"
  );
  const lastButton = paginationContainer.querySelector(
    ".unavailable__pagination-btn--last"
  );
  const totalItemsEl = paginationContainer.querySelector(
    ".unavailable__pagination-total-items"
  );

  const paginationText = document.querySelector(".unavailable-wrapper").dataset
    .paginationText;

  let currentPage = 1;
  let totalPages = 1;
  let totalItems = 0;

  const updatePaginationInfo = () => {
    if (pagesContainer) {
      pagesContainer.innerHTML = `${currentPage} ${paginationText} ${totalPages}`;
    }
  };

  const updatePaginationState = (data) => {
    currentPage = data.current_page;
    totalPages = data.total_pages;
    totalItems = data.total_products;

    if (totalItemsEl) {
      totalItemsEl.textContent = totalItems;
    }

    if (firstButton) firstButton.disabled = currentPage <= 1;
    if (prevButton) prevButton.disabled = currentPage <= 1;
    if (nextButton) nextButton.disabled = currentPage >= totalPages;
    if (lastButton) lastButton.disabled = currentPage >= totalPages;

    updatePaginationInfo();
  };

  if (firstButton) {
    firstButton.addEventListener("click", () => {
      if (currentPage !== 1) {
        updateProductsList();
      }
    });
  }

  if (prevButton) {
    prevButton.addEventListener("click", () => {
      if (currentPage > 1) {
        updateProductsList(currentPage - 1, totalPages);
      }
    });
  }

  if (nextButton) {
    nextButton.addEventListener("click", () => {
      if (currentPage < totalPages) {
        updateProductsList(currentPage + 1, totalPages);
      }
    });
  }

  if (lastButton) {
    lastButton.addEventListener("click", () => {
      if (currentPage !== totalPages) {
        updateProductsList(totalPages, totalPages);
      }
    });
  }

  return {
    updatePaginationState,
    reset: () => {
      currentPage = 1;
      totalPages = 1;
      totalItems = 0;
      if (totalItemsEl) totalItemsEl.textContent = "0";
      if (firstButton) firstButton.disabled = true;
      if (prevButton) prevButton.disabled = true;
      if (nextButton) nextButton.disabled = true;
      if (lastButton) lastButton.disabled = true;
      updatePaginationInfo();
    },
  };
}
