import getUnavailableProducts from "../api/getUnavailableProducts";
import deleteUnavailableProduct from "../api/deleteUnavailableProduct";
import deleteAllUnavailableProducts from "../api/deleteAllUnavailableProducts";
import addUnavailableProduct from "../api/addUnavailableProduct";
import toggleRemoveAllButton from "./toggleRemoveAllButton";
import showAlert from "./showAlert";

export default async function loadUnavailableProducts(
  paginationHandler = null
) {
  const tableBody = document.querySelector(
    ".unavailable__table--unavailable tbody"
  );
  const removeAllButton = document.querySelector(".unavailable__remove-all");

  if (!tableBody || !removeAllButton) return;

  removeAllButton.replaceWith(removeAllButton.cloneNode(true));
  const newRemoveAllButton = document.querySelector(".unavailable__remove-all");

  const loaderHTML = `
    <tr>
      <td colspan="7" style="text-align: center">
        <div class="unavailable__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-unavailable" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-unavailable)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  tableBody.innerHTML = loaderHTML;

  try {
    const products = await getUnavailableProducts();

    toggleRemoveAllButton(products?.length > 0);

    const removeText = document.querySelector(".unavailable-wrapper")?.dataset
      ?.removeText;
    const courierText = document.querySelector(".unavailable-wrapper")?.dataset
      ?.courierText;
    const parcelLockerText = document.querySelector(".unavailable-wrapper")
      ?.dataset?.parcelLockerText;

    tableBody.innerHTML = products?.length
      ? products
          .map(
            (product, index) => `
        <tr data-product-id="${product.id}">
          <td class="unavailable__td unavailable__td--count">${index + 1}.</td>
          <td class="unavailable__td unavailable__td--product-name">
            <a href="/wp-admin/post.php?post=${
              product.product_id
            }&action=edit" target="_blank">
              ${product.title}
            </a>
          </td>
          <td class="unavailable__td unavailable__td--id">${
            product.product_id
          }</td>
          <td class="unavailable__td unavailable__td--actions">
            <div class="unavailable__checkbox-wrapper">
              <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--courier" data-product-id="${
                product.product_id
              }" ${
              product.delivery_type === "2" || product.delivery_type === "3"
                ? "checked"
                : ""
            } />
              <label class="unavailable__checkbox-label">
                  ${courierText}
              </label>
            </div>
            <div class="unavailable__checkbox-wrapper">
              <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--parcel-locker" data-product-id="${
                product.product_id
              }" ${
              product.delivery_type === "1" || product.delivery_type === "3"
                ? "checked"
                : ""
            } />
              <label class="unavailable__checkbox-label">
                  ${parcelLockerText}
              </label>
            </div>
            <div>
              <button class="inpost-btn inpost-btn--remove-mini">
                <img src="${
                  document.querySelector(".unavailable-wrapper").dataset
                    .pluginUrl
                }../../../assets/img/hp-remove.svg" alt="">
                <span>${removeText}</span>
              </button>
            </div>
          </td>
        </tr>
      `
          )
          .join("")
      : `
        <tr>
          <td colspan="7" style="text-align: center;" class="unavailable__no-results-main>
            ${
              document.querySelector(".unavailable-wrapper").dataset
                .noResultsMessage
            }
          </td>
        </tr>
      `;

    const handler = paginationHandler || window.unavailablePaginationHandler;

    if (handler) {
      const mainSearchInput = document.querySelector(
        ".unavailable__search-main"
      );
      if (mainSearchInput) {
        mainSearchInput.value = "";
      }

      handler.reinitialize();
    }

    const buttons = tableBody.querySelectorAll(".inpost-btn--remove-mini");
    buttons.forEach((button) => {
      const newButton = button.cloneNode(true);
      button.parentNode.replaceChild(newButton, button);
    });

    tableBody.querySelectorAll(".unavailable__checkbox").forEach((checkbox) => {
      checkbox.addEventListener("change", async (e) => {
        const row = e.target.closest("tr");
        const courierCheckbox = row.querySelector(
          ".unavailable__checkbox--courier"
        );
        const parcelLockerCheckbox = row.querySelector(
          ".unavailable__checkbox--parcel-locker"
        );

        const isCourierChecked = courierCheckbox.checked;
        const isParcelLockerChecked = parcelLockerCheckbox.checked;

        try {
          if (!isCourierChecked && !isParcelLockerChecked) {
            const removeButton = row.querySelector(".inpost-btn--remove-mini");
            if (removeButton) {
              removeButton.click();
            }
          } else {
            row.classList.add("removing");

            let deliveryType;
            if (isCourierChecked && isParcelLockerChecked) {
              deliveryType = "3";
            } else if (isCourierChecked) {
              deliveryType = "2";
            } else if (isParcelLockerChecked) {
              deliveryType = "1";
            }

            await addUnavailableProduct([
              {
                id: row.querySelector(".unavailable__td--id")
                  .textContent,
                delivery_type: deliveryType,
              },
            ]);

            row.classList.remove("removing");
          }
        } catch (error) {
          console.error("Error updating product delivery type:", error);
          showAlert(error);
          e.target.checked = !e.target.checked;
          row.classList.remove("removing");
        }
      });
    });

    tableBody.querySelectorAll(".inpost-btn--remove-mini").forEach((button) => {
      button.addEventListener("click", async (e) => {
        const row = e.target.closest("tr");
        const productId = row.dataset.productId;
        const originalContent = row.innerHTML;

        try {
          row.classList.add("removing");
          await deleteUnavailableProduct(productId);

          setTimeout(() => {
            row.remove();

            if (handler) {
              handler.refresh();
            } else {
              const remainingRows = tableBody.querySelectorAll("tr");
              remainingRows.forEach((tr, index) => {
                const countWrapper = tr.querySelector(
                  ".unavailable__td--count"
                );
                if (countWrapper) {
                  countWrapper.innerHTML = `
                    <div class="unavailable__td--count-wrapper">
                      <span>${index + 1}.</span>
                    </div>
                  `;
                }
              });
            }

            const totalItemsEl = document.querySelector(
              "#unavailable-pagination .unavailable__pagination-total-items"
            );
            if (totalItemsEl && !handler) {
              const currentTotal = parseInt(totalItemsEl.textContent) - 1;
              totalItemsEl.textContent = currentTotal;
            }

            if (!tableBody.querySelectorAll("tr[data-product-id]").length) {
              tableBody.innerHTML = `
                <tr>
                  <td colspan="7" style="text-align: center;" class="unavailable__no-results-main">
                    ${
                      document.querySelector(".unavailable-wrapper").dataset
                        .noResultsMessage
                    }
                  </td>
                </tr>
              `;

              const removeAllButton = document.querySelector(
                ".unavailable__remove-all"
              );
              if (removeAllButton) {
                removeAllButton.style.display = "none";
              }

              if (totalItemsEl && !handler) {
                totalItemsEl.textContent = "0";
              }
            }
          }, 300);
        } catch (error) {
          console.error("Error removing product:", error);
          showAlert(error);
          row.classList.remove("removing");
          row.innerHTML = originalContent;
        }
      });
    });

    newRemoveAllButton.addEventListener("click", async () => {
      try {
        const rows = tableBody.querySelectorAll("tr");

        rows.forEach((row) => row.classList.add("removing"));

        await deleteAllUnavailableProducts();

        setTimeout(() => {
          tableBody.innerHTML = `
            <tr>
              <td colspan="7" style="text-align: center;" class="unavailable__no-results-main">
                ${
                  document.querySelector(".unavailable-wrapper").dataset
                    .noResultsMessage
                }
              </td>
            </tr>
          `;
          newRemoveAllButton.style.display = "none";

          if (handler) {
            handler.refresh();
          }
        }, 300);
      } catch (error) {
        showAlert(error);
        console.error("Error removing all products:", error);
        rows.forEach((row) => row.classList.remove("removing"));
      }
    });
  } catch (error) {
    console.error("Error loading hot products:", error);
    showAlert(error);
    toggleRemoveAllButton(false);
    tableBody.innerHTML = `
      <tr>
        <td colspan="7" style="text-align: center; color: var(--unavailable-red);">
          ${
            document.querySelector(".unavailable-wrapper").dataset
              .apiErrorMessage
          }
        </td>
      </tr>
    `;
  }
}
