import showModal from "./unavailable/modal/showModal";
import hideModals from "./unavailable/modal/hideModals";
import loadCategories from "./unavailable/modal/loadCategories";
import loadSearchs from "./unavailable/modal/loadSearchs";
import productsBackButton from "./unavailable/modal/productsBackButton";
import clearSearchs from "./unavailable/modal/clearSearchs";
import resetCategoriesSearch from "./unavailable/modal/resetCategoriesSearch";
import loadUnavailableProducts from "./unavailable/modal/loadUnavailableProducts";
import handleProductSelection from "./unavailable/modal/handleProductSelection";
import resetSelectedProducts from "./unavailable/modal/resetSelectedProducts";
import handleConfirmationModal from "./unavailable/modal/handleConfirmationModal";
import handleAddedProductsSave from "./unavailable/modal/handleAddedProductsSave";
import filterMainTable from "./unavailable/modal/filterMainTable";
import handleMainTablePagination from "./unavailable/modal/handleMainTablePagination";

window.unavailablePaginationHandler = null;

window.addEventListener("load", function () {
  const productsWrapper = document.querySelector(".unavailable-wrapper");

  if (!productsWrapper) {
    return;
  }

  const paginationHandler = handleMainTablePagination();
  window.unavailablePaginationHandler = paginationHandler;

  loadUnavailableProducts(paginationHandler);

  loadCategories();

  const popupTable = productsWrapper?.querySelector(".unavailable-popup-table");
  const overlay = productsWrapper?.querySelector(".overlay");
  const selectProductsButton = productsWrapper?.querySelector(
    ".unavailable-select-products"
  );
  const closePopupButton = popupTable?.querySelector(
    ".unavailable__popup-close"
  );
  const cancelButton = productsWrapper?.querySelector(
    ".unavailable__table-actions-categories-btn"
  );

  const closeElements = [closePopupButton, cancelButton, overlay];

  closeElements.forEach((element) => {
    element &&
      element.addEventListener("click", () => {
        hideModals();
        resetCategoriesSearch();
        clearSearchs();
      });
  });

  selectProductsButton.addEventListener("click", () => {
    showModal(popupTable, overlay);
    resetCategoriesSearch();
    clearSearchs();
    resetSelectedProducts();
  });

  loadSearchs();
  productsBackButton();
  handleProductSelection();
  handleAddedProductsSave();
  handleConfirmationModal();
  filterMainTable(paginationHandler);
});
