export default function showAlert(text) {
  const unavailableWrapper = document.querySelector(".unavailable-wrapper");

  if (!unavailableWrapper) return;

  const existingAlerts = document.querySelectorAll(".unavailable-error-alert");

  if (existingAlerts.length > 0) {
    existingAlerts.forEach((alert) => {
      alert.remove();
    });
  }

  const template = `    
        <div class="unavailable-error-alert__content">
            <h3 class="unavailable-error-alert__title">${unavailableWrapper.dataset.apiErrorTitle}</h3>
            <p class="unavailable-error-alert__text">${text}</p>
        </div>`;

  const alert = document.createElement("div");
  alert.classList = "unavailable-error-alert unavailable-error-alert--active";
  alert.innerHTML = template;

  unavailableWrapper.appendChild(alert);

  setTimeout(() => {
    alert.classList.remove("unavailable-error-alert--active");
  }, 5000);
}
