export default function filterMainTable(paginationHandler) {
  const mainSearchInput = document.querySelector(".unavailable__search-main");

  if (!mainSearchInput) {
    return;
  }

  mainSearchInput.addEventListener("input", (e) => {
    if (paginationHandler) {
      paginationHandler.showPage(1);
    } else {
      const searchValue = e.target.value.toLowerCase();
      const mainTableRows = document.querySelectorAll(
        ".unavailable__table--unavailable tbody tr"
      );

      let visibleCount = 0;
      mainTableRows.forEach((row) => {
        const productName =
          row
            .querySelector(".unavailable__td--product-name")
            ?.textContent?.toLowerCase() || "";
        const productId =
          row
            .querySelector(".unavailable__td--id")
            ?.textContent?.toLowerCase() || "";

        const isVisible =
          productName.includes(searchValue) || productId.includes(searchValue);

        row.style.display = isVisible ? "" : "none";
        if (isVisible) visibleCount++;
      });

      const noResultsText = document.querySelector(".unavailable-wrapper")
        ?.dataset?.noResultsMessage;

      let noResultsMessage = document.querySelector(
        ".unavailable__no-results-main"
      );
      const tbody = document.querySelector(
        ".unavailable__table--unavailable tbody"
      );

      if (visibleCount === 0) {
        if (!noResultsMessage) {
          const messageRow = document.createElement("tr");
          messageRow.className = "unavailable__no-results-main";
          messageRow.innerHTML = `<td colspan="4" style="text-align: center;">${noResultsText}</td>`;
          tbody.appendChild(messageRow);
          noResultsMessage = messageRow;
        }
        noResultsMessage.style.display = "";
      } else {
        if (noResultsMessage) {
          noResultsMessage.style.display = "none";
        }
      }
    }
  });
}
