let currentController = null;

export default async function getProductsList(categoryId, search, page = 1) {
  const location = window.location.origin;
  const endpoint = "/wp-json/inpost/v1/izi/product/list";

  const categoryParam = categoryId ? `category_id=${categoryId}` : "";
  const searchParam = search ? `&search=${search}` : "";
  const pageParam = `&page=${page}`;
  const typeParam = `&type=hotproduct`;

  if (currentController) currentController.abort();

  currentController = new AbortController();

  try {
    const response = await fetch(
      `${location}${endpoint}?${categoryParam}${typeParam}${searchParam}${pageParam}`,
      {
        credentials: "same-origin",
        headers: {
          "Content-Type": "application/json",
          cache: "no-cache",
        },
        signal: currentController.signal,
      }
    );

    const data = await response.json();
    if (!response.ok) throw new Error(data.error);
    if (response.status !== 200) return;

    currentController = null;
    return data;
  } catch (error) {
    if (error.name === "AbortError") {
      throw new Error("Request cancelled");
    }
    throw error;
  }
}
