import addUnavailableProduct from "../api/addUnavailableProduct";
import showAlert from "./showAlert";
import loadUnavailableProducts from "./loadUnavailableProducts";
import hideModals from "./hideModals";

export default function handleProductSelection() {
  const productsTable = document.querySelector(".unavailable__table--products");
  const saveButton = document.querySelector(
    ".unavailable__table-actions-products-save-btn"
  );

  if (!productsTable || !saveButton) return;

  const oldHandler = productsTable.getAttribute("data-handler");
  if (oldHandler) {
    productsTable.removeEventListener("change", window[oldHandler]);
    saveButton.removeEventListener("click", window[oldHandler + "_save"]);
  }

  const selectedProducts = new Map();

  const loaderHTML = `
    <tr>
      <td colspan="4" style="text-align: center">
        <div class="unavailable__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-save" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-save)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  const handleChange = (e) => {
    const checkbox = e.target;
    if (!checkbox.matches('input[type="checkbox"].unavailable__checkbox'))
      return;

    const row = checkbox.closest("tr");
    const productId = row.dataset.productId;
    if (!productId) return;

    const courierCheckbox = row.querySelector(
      ".unavailable__checkbox--courier"
    );
    const parcelLockerCheckbox = row.querySelector(
      ".unavailable__checkbox--parcel-locker"
    );

    const courierExcluded = courierCheckbox?.checked || false;
    const parcelLockerExcluded = parcelLockerCheckbox?.checked || false;

    if (courierExcluded || parcelLockerExcluded) {
      let deliveryType;
      if (courierExcluded && parcelLockerExcluded) {
        deliveryType = 3;
      } else if (courierExcluded) {
        deliveryType = 2;
      } else {
        deliveryType = 1;
      }

      selectedProducts.set(productId, deliveryType);
      row.classList.add("selected");
      row.style.backgroundColor = "#f0f8ff";
    } else {
      selectedProducts.delete(productId);
      row.classList.remove("selected");
      row.style.backgroundColor = "";
    }

    saveButton.classList.toggle("disabled", selectedProducts.size === 0);
  };

  const handleSave = async () => {
    if (selectedProducts.size === 0) return;

    saveButton.classList.add("disabled");
    const tableBody = productsTable.querySelector("tbody");
    const paginationButtons = document.querySelectorAll(
      "#products-pagination .unavailable__pagination-btn"
    );
    tableBody.innerHTML = loaderHTML;

    paginationButtons.forEach((button) => {
      button.disabled = true;
    });

    const productsArray = Array.from(selectedProducts.entries()).map(
      ([id, deliveryType]) => ({
        id: id,
        delivery_type: deliveryType,
      })
    );

    let response;
    try {
      response = await addUnavailableProduct(productsArray);
    } catch (error) {
      console.error("Error adding unavailable products:", error);
      showAlert(error);
    } finally {
      selectedProducts.clear();
      saveButton.classList.remove("disabled");

      const rows = productsTable.querySelectorAll("tbody tr");
      rows.forEach((row) => {
        row.classList.remove("selected");
        row.style.backgroundColor = "";
        const checkboxes = row.querySelectorAll(".unavailable__checkbox");
        checkboxes.forEach((cb) => (cb.checked = false));
      });

      loadUnavailableProducts(window.unavailablePaginationHandler);
      hideModals();
    }
  };

  const handlerId = "handler_" + Date.now();
  window[handlerId] = handleChange;
  window[handlerId + "_save"] = handleSave;
  productsTable.setAttribute("data-handler", handlerId);

  productsTable.addEventListener("change", handleChange);
  saveButton.addEventListener("click", handleSave);
}
