import clearSearchs from "./clearSearchs";
import resetSelectedProducts from "./resetSelectedProducts";

export default function productsBackButton() {
  const backButton = document.querySelector(
    ".unavailable__table-actions-products-back-btn"
  );
  const confirmation = document.querySelector(".unavailable-confirmation");

  if (!backButton || !confirmation) return;

  backButton.addEventListener("click", () => {
    const hasSelectedProducts =
      document.querySelectorAll(
        ".unavailable__table--products input[type='checkbox']:checked"
      ).length > 0;

    if (hasSelectedProducts) {
      confirmation.classList.add("unavailable-confirmation--active");
    } else {
      const categoriesWrapper = document.querySelector(
        ".unavailable__table-wrapper--categories"
      );
      const productsWrapper = document.querySelector(
        ".unavailable__table-wrapper--products"
      );

      categoriesWrapper.classList.remove("unavailable__table-wrapper--hidden");
      productsWrapper.classList.add("unavailable__table-wrapper--hidden");
      clearSearchs();
      resetSelectedProducts();
    }
  });
}
