import getProductsList from "../api/getProductsList";
import handleProductSelection from "./handleProductSelection";
import handlePagination from "./handlePagination";
import debounce from "../helpers/debounce";

let pagination = null;

export default async function updateProductsList(page = 1, totalPages = null) {
  const productsContainer = document.querySelector(
    ".unavailable__table--products tbody"
  );
  if (!productsContainer) return;

  const wrapper = document.querySelector(".unavailable-wrapper");
  const categoryId = document.querySelector(
    ".unavailable__table-wrapper--products"
  ).dataset.categoryId;
  const noResultsMessage = wrapper.dataset.noResultsMessage;
  const searchInput = document.querySelector(".unavailable__search--products");
  const saveButton = document.querySelector(
    ".unavailable__table-actions-products-save-btn"
  );

  const totalItemsEl = document.querySelector(
    "#products-pagination .unavailable__pagination-total-items"
  );

  const paginationText = document.querySelector(".unavailable-wrapper").dataset
    .paginationText;

  const pagesContainer = document.querySelector(
    "#products-pagination .unavailable__pagination-pages"
  );

  const paginationButtons = document.querySelectorAll(
    "#products-pagination .unavailable__pagination-btn"
  );

  saveButton.classList.add("disabled");

  paginationButtons.forEach((button) => {
    button.disabled = true;
  });

  const totalPagesText = totalPages || 1;

  if (totalItemsEl) {
    totalItemsEl.textContent = 0;
  }

  if (pagesContainer) {
    pagesContainer.textContent = `${page} ${paginationText} ${totalPagesText}`;
  }

  if (!pagination) {
    pagination = handlePagination(updateProductsList);
  }

  const loaderHTML = `
    <tr>
      <td colspan="4" style="text-align: center">
        <div class="unavailable__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-products" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-products)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  productsContainer.innerHTML = loaderHTML;

  try {
    const productsData = await getProductsList(
      categoryId,
      searchInput?.value || "",
      page
    );

    const { products, total_pages, total_products, current_page } =
      productsData;

    pagination.updatePaginationState({
      current_page,
      total_pages,
      total_products,
    });

    if (!products?.length) {
      productsContainer.innerHTML = `
        <tr>
          <td colspan="4" style="text-align: center;">
            ${noResultsMessage}
          </td>
        </tr>
      `;
      return;
    }

    const itemsPerPage = products.length;
    const startIndex = (current_page - 1) * itemsPerPage;
    const productTable = document.querySelector(
      ".unavailable__table-wrapper--products"
    );

    const categoryIdText = productTable.dataset.categoryId;
    const categoryNameText = productTable.dataset.categoryName;

    productsContainer.innerHTML = `
      <tr style="position: relative;">
        <td class="unavailable__td unavailable__td--count unavailable__td--bg-gray"></td>
        <td class="unavailable__td unavailable__td--product-name unavailable__td--font-bold unavailable__td--position-left unavailable__td--bg-gray"><span>${categoryNameText}</span></td>
        <td class="unavailable__td unavailable__td--id unavailable__td--bg-gray">${categoryIdText}</td>
        <td class="unavailable__td unavailable__td--id unavailable__td--bg-gray"></td>
        <td class="unavailable__td unavailable__td--id unavailable__td--bg-gray"></td>
      </tr>
    `;

    const parcelLockerText = document.querySelector(".unavailable-wrapper")
      .dataset.parcelLockerText;
    const courierText = document.querySelector(".unavailable-wrapper").dataset
      .courierText;

    productsContainer.innerHTML += products
      .map(
        (product, index) => `
          <tr data-product-id="${product.id}">
            <td class="unavailable__td unavailable__td--count">
              <span>${startIndex + index + 1}.</span>
            </td>
            <td class="unavailable__td unavailable__td--product-name">${
              product.name
            }</td>
            <td class="unavailable__td unavailable__td--id">${product.id}</td>
            <td class="unavailable__td unavailable__td--actions">
              <div class="unavailable__checkbox-wrapper">
                <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--courier" />
                <label class="unavailable__checkbox-label">
                    ${courierText}
                </label>
              </div>
              <div class="unavailable__checkbox-wrapper">
                <input type="checkbox" class="unavailable__checkbox unavailable__checkbox--parcel-locker" />
                <label class="unavailable__checkbox-label">
                    ${parcelLockerText}
                </label>
              </div>
            </td>
          </tr>
        `
      )
      .join("");

    handleProductSelection();
  } catch (error) {
    console.error("Error updating products list:", error);
    productsContainer.innerHTML = loaderHTML;
    pagination.reset();
  }
}

document.querySelector(".unavailable__search--products")?.addEventListener(
  "input",
  debounce(() => {
    updateProductsList();
  }, 300)
);
