import getCategoryList from "../api/getCategoryList";
import addCategoriesLinks from "./addCategoriesLinks";
import showAlert from "./showAlert";

export default async function loadCategories() {
  const categoriesTable = document.querySelector(
    ".unavailable__table--categories"
  );
  const categoriesTableBody = categoriesTable?.querySelector("tbody");

  if (!categoriesTable || !categoriesTableBody) {
    return;
  }

  const loaderHTML = `
    <tr>
      <td colspan="3" style="text-align: center">
        <div class="unavailable__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  categoriesTableBody.innerHTML = loaderHTML;

  try {
    const categories = await getCategoryList();
    categoriesTableBody.innerHTML = "";

    const pluginUrl = document.querySelector(".unavailable-wrapper").dataset
      .pluginUrl;

    await Promise.all(
      categories.map(async (category) => {
        const row = document.createElement("tr");
        row.innerHTML = `
        <td class="unavailable__td unavailable__td--product-name unavailable__td--font-bold">${category.name}</td>
        <td class="unavailable__td unavailable__td--id">${category.id}</td>
        <td class="unavailable__td unavailable__td--actions">
          <div class="unavailable__product-link" data-category-id="${category.id}" data-category-name="${category.name}">
            <img src="${pluginUrl}../../../assets/img/hp-arrow.svg" alt="">
          </div>
        </td>
      `;
        categoriesTableBody.appendChild(row);
      })
    );

    addCategoriesLinks();
  } catch (error) {
    showAlert(error);
    const apiErrorMessage = document.querySelector(".unavailable-wrapper")
      .dataset.apiErrorMessage;

    categoriesTableBody.innerHTML = `
      <tr>
        <td colspan="3" style="text-align: center; color: var(--unavailable-red);">
          ${apiErrorMessage}
        </td>
      </tr>
    `;
    console.error("Błąd podczas ładowania kategorii:", error);
  }
}
