export default function handleMainTablePagination() {
  const paginationContainer = document.querySelector("#unavailable-pagination");
  const pagesContainer = paginationContainer?.querySelector(
    ".unavailable__pagination-pages"
  );
  const firstButton = paginationContainer?.querySelector(
    ".unavailable__pagination-btn--first"
  );
  const prevButton = paginationContainer?.querySelector(
    ".unavailable__pagination-btn--prev"
  );
  const nextButton = paginationContainer?.querySelector(
    ".unavailable__pagination-btn--next"
  );
  const lastButton = paginationContainer?.querySelector(
    ".unavailable__pagination-btn--last"
  );
  const totalItemsEl = paginationContainer?.querySelector(
    ".unavailable__pagination-total-items"
  );

  if (!paginationContainer) {
    return {
      init: () => {},
      refresh: () => {},
      reinitialize: () => {},
      showPage: () => {},
      getCurrentPage: () => 1,
      getTotalPages: () => 1,
    };
  }

  const paginationText =
    document.querySelector(".unavailable-wrapper")?.dataset?.paginationText ||
    "z";

  const ITEMS_PER_PAGE = 10;
  let currentPage = 1;
  let totalPages = 1;
  let allRows = [];
  let filteredRows = [];

  let searchEventController = new AbortController();

  const updatePaginationInfo = () => {
    if (pagesContainer) {
      pagesContainer.innerHTML = `${currentPage} ${paginationText} ${totalPages}`;
    }
  };

  const updatePaginationButtons = () => {
    if (firstButton) firstButton.disabled = currentPage <= 1;
    if (prevButton) prevButton.disabled = currentPage <= 1;
    if (nextButton) nextButton.disabled = currentPage >= totalPages;
    if (lastButton) lastButton.disabled = currentPage >= totalPages;
  };

  const getAllRows = () => {
    const tbody = document.querySelector(
      ".unavailable__table--unavailable tbody"
    );
    if (!tbody) return [];

    return Array.from(tbody.querySelectorAll("tr")).filter(
      (row) =>
        !row.classList.contains("unavailable__no-results-main") &&
        row.querySelector(".unavailable__td--product-name")
    );
  };

  const getFilteredRows = () => {
    const searchInput = document.querySelector(".unavailable__search-main");
    const searchValue = searchInput?.value.toLowerCase() || "";

    if (!searchValue) return allRows;

    return allRows.filter((row) => {
      const productName =
        row
          .querySelector(".unavailable__td--product-name")
          ?.textContent?.toLowerCase() || "";
      const productId =
        row.querySelector(".unavailable__td--id")?.textContent?.toLowerCase() ||
        "";
      return (
        productName.includes(searchValue) || productId.includes(searchValue)
      );
    });
  };

  const updateRowNumbers = (rows) => {
    rows.forEach((row, index) => {
      const countCell = row.querySelector(".unavailable__td--count");
      if (countCell) {
        const globalIndex = (currentPage - 1) * ITEMS_PER_PAGE + index + 1;
        countCell.textContent = `${globalIndex}.`;
      }
    });
  };

  const showPage = (page) => {
    currentPage = page;
    filteredRows = getFilteredRows();
    totalPages = Math.max(1, Math.ceil(filteredRows.length / ITEMS_PER_PAGE));

    if (currentPage > totalPages) {
      currentPage = totalPages;
    }

    const tbody = document.querySelector(
      ".unavailable__table--unavailable tbody"
    );
    if (!tbody) return;

    allRows.forEach((row) => {
      row.style.display = "none";
    });

    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    const endIndex = startIndex + ITEMS_PER_PAGE;
    const pageRows = filteredRows.slice(startIndex, endIndex);

    pageRows.forEach((row) => {
      row.style.display = "";
    });

    updateRowNumbers(pageRows);

    if (totalItemsEl) {
      totalItemsEl.textContent = filteredRows.length;
    }

    const noResultsMessage = tbody.querySelector(
      ".unavailable__no-results-main"
    );
    if (filteredRows.length === 0) {
      if (!noResultsMessage) {
        const messageRow = document.createElement("tr");
        messageRow.className = "unavailable__no-results-main";
        messageRow.innerHTML = `<td colspan="4" style="text-align: center;">${
          document.querySelector(".unavailable-wrapper")?.dataset
            ?.noResultsMessage || "Brak wyników"
        }</td>`;
        tbody.appendChild(messageRow);
      } else {
        noResultsMessage.style.display = "";
      }
    } else {
      if (noResultsMessage) {
        noResultsMessage.style.display = "none";
      }
    }

    updatePaginationInfo();
    updatePaginationButtons();
  };

  const initSearchListener = () => {
    searchEventController.abort();
    searchEventController = new AbortController();

    const searchInput = document.querySelector(".unavailable__search-main");
    if (searchInput) {
      searchInput.addEventListener(
        "input",
        () => {
          showPage(1);
        },
        { signal: searchEventController.signal }
      );
    }
  };

  const init = () => {
    allRows = getAllRows();
    initSearchListener();
    showPage(1);
  };

  const refresh = () => {
    allRows = getAllRows();
    showPage(currentPage);
  };

  const reinitialize = () => {
    allRows = getAllRows();
    initSearchListener();
    showPage(1);
  };

  if (firstButton) {
    firstButton.addEventListener("click", () => {
      if (currentPage !== 1) {
        showPage(1);
      }
    });
  }

  if (prevButton) {
    prevButton.addEventListener("click", () => {
      if (currentPage > 1) {
        showPage(currentPage - 1);
      }
    });
  }

  if (nextButton) {
    nextButton.addEventListener("click", () => {
      if (currentPage < totalPages) {
        showPage(currentPage + 1);
      }
    });
  }

  if (lastButton) {
    lastButton.addEventListener("click", () => {
      if (currentPage !== totalPages) {
        showPage(totalPages);
      }
    });
  }

  return {
    init,
    refresh,
    reinitialize,
    showPage,
    getCurrentPage: () => currentPage,
    getTotalPages: () => totalPages,
  };
}
